// `runs` and `decks` are populated with the current fleet view;
// in steady state (`since_seq > 0`) `decks` is omitted and
// `decks_delta` carries only the touched-since slice. `server_seq`
// is the highest event seq known to the orchestrator at response
// time — clients use it as the next request's `since_seq`.
type StateSnapshot struct {
	// Decks Bootstrap-only authoritative slice for every deck. Omitted
	// from delta responses (since_seq > 0); use `decks_delta` there.
	Decks *[]Deck `json:"decks,omitempty"`

	// DecksDelta Delta-only. Decks whose row was touched since `since_seq`:
	// union of (a) decks referenced by any event with seq >
	// since_seq and (b) decks whose `last_heartbeat_at` advanced
	// inside the recent freshness window (orchestrator-chosen,
	// currently 5s). Clients merge by `id` into the existing
	// decks cache instead of replacing wholesale. Bounds steady
	// poll cost by activity rather than fleet size (see S3 in
	// analysis/inefficiencies/inefficiencies.md).
	DecksDelta *[]Deck `json:"decks_delta,omitempty"`
	Events     []Event `json:"events"`

	// Runs Bootstrap-only. Omitted from delta responses.
	Runs      *[]RunSummary `json:"runs,omitempty"`
	ServerSeq int64         `json:"server_seq"`
}

